parameters.content:
## 自家訂單 → LINE Notify

@trigger: webhook POST /order
@input: { order_id, customer_name, amount, items[] }
@step: 組訊息 "🛒 新訂單 #{order_id} {customer_name} 共 ${amount}"
@output: LINE Notify (httpRequest POST https://notify-api.line.me/api/notify, Header Auth)
@on-error: continueOnFail (LINE 暫時失敗不阻斷)

@assume: 已有 LINE Notify access token
@assume: token 已在 n8n credentials 設為 "Header Auth: lineNotify"

assignments.value:
=🛒 新訂單 #{{ $json.body.order_id }}
客戶：{{ $json.body.customer_name }}
金額：${{ $json.body.amount }}
